<template>
    <div class="demo-content">
        <h1>3D模型沿轨迹运动</h1>
        <h4>Tip:以下地图坐标从高德地图拾取,需要进行坐标转换</h4>
        <h2>根据指定路径运动</h2>
        <h4>Tip:由于路径上两点之间间隔过大，导致小车运动会有偏移现象</h4>
        <div class="field">
            <div class="field-left">
                <pre>
                    <code-copy :code="threeCode" :btnClssName="'copy-btn'"></code-copy>
                    <code>{{threeCode}}</code>
                </pre>
            </div>
            <div class="field-right">
                <base-map :mapOptions="mapOptions" :hasThreeModel="true" @getMap="getMap($event)" @getTb="getTb($event)"></base-map>
            </div>
        </div>
    </div>
</template>

<script>
import BaseMap from "../../components/BaseMap.vue";
import CodeCopy from "../../components/CodeCopy.vue";
import { reactive, ref, onMounted, onUpdated, onBeforeUnmount } from "vue";
import { Utils } from "../../utils/utils";
// import coordtransform from "coordtransform";

export default {
    components: {
        BaseMap,
        CodeCopy
    },
    setup() {
        const mapOptions = reactive({
            center: {
                lon: 118.784135,
                lat: 32.041808
            },
            zoom: 17,
            pitch: 60
        });
        let map = reactive(null);
        let tb = reactive(null);
        let busModels = reactive([]);
        let modelsMap = reactive({});
        const gpsData = reactive([{ lon: 118.784135, lat: 32.041808, type: "srt" }]);

        const getMap = data => {
            map = data;
        };

        const getTb = data => {
            tb = data;
            addThreeLayer();
        };

        const linePath = reactive({
            properties: {},
            type: "Feature",
            geometry: {
                type: "LineString",
                coordinates: [
                    [118.77870961386009, 32.043888923737626],
                    [118.7761474096065, 32.04400290156785],
                    [118.77494259610859, 32.04180105593608],
                    [118.77852145919252, 32.040233057268765],
                    [118.77882023675852, 32.04014796797969],
                    [118.78210209065588, 32.03946403417204],
                    [118.78200657309276, 32.038046869539585],
                    [118.78285399896788, 32.03782167428599],
                    [118.78369397474717, 32.04082073739855],
                    [118.78418317347155, 32.04339154134594],
                    [118.782836636799, 32.04353213839404],
                    [118.78342828024591, 32.04679039527164],
                    [118.77888275849722, 32.04796719895893],
                    [118.7788519859738, 32.036904849292156]
                ]
            }
        });
        let line = reactive(null);

        const threeCode = ref(`// 轨迹运动
const track = data => {
    var options = {
        path: data.geometry.coordinates,
        duration: 40000
    };

    busModels[0].followPath(options, () => {
        // tb.remove(line);
    });
    let lineGeometry = options.path;
    line = tb.line({
        geometry: lineGeometry,
        width: 5,
        color: "steelblue"
    });
    tb.add(line);
};
        `);

        // 添加3D模型图层
        const addThreeLayer = () => {
            map.addLayer({
                id: "custom_layer",
                type: "custom",
                renderingMode: "3d",
                onAdd: () => {
                    loadModels().then(models => {
                        modelsMap = {};
                        models.forEach(item => {
                            modelsMap[item.name] = item.model;
                        });
                        addModelsToMap();
                    });
                },
                render: () => {
                    if (map) {
                        tb.update();
                    }
                }
            });
        };

        // 添加模型到地图上
        const addModelsToMap = () => {
            gpsData.forEach(() => {
                const model = modelsMap["srt"].duplicate();
                model.setCoords(linePath.geometry.coordinates[0]);
                // 默认为逆时针旋转
                model.setRotation({
                    x: 0,
                    y: 0,
                    z: 0
                });
                let labelDiv = `<h1 style="color:blue">这是标签</h1>`;
                model.addLabel(labelDiv, true, model.anchor, 1);
                model.addEventListener("ObjectChanged", onObjectChanged, false);
                tb.add(model);
                busModels.push(model);
            });
            track(linePath);
            map.triggerRepaint();
        };

        // 加载模型
        const loadModels = () => {
            const modelUrls = [
                { url: location.origin + process.env.VUE_APP_ASSETS_PREFIX + "/assets/models/srt.gltf", name: "srt" },
                { url: location.origin + process.env.VUE_APP_ASSETS_PREFIX + "/assets/models/brt.gltf", name: "brt" },
                { url: location.origin + process.env.VUE_APP_ASSETS_PREFIX + "/assets/models/plane.glb", name: "plane" },
                { url: location.origin + process.env.VUE_APP_ASSETS_PREFIX + "/assets/models/soldier.glb", name: "soldier" }
            ];
            const promiseArray = [];
            modelUrls.forEach(item => {
                const option = {
                    obj: item.url,
                    type: "gltf",
                    scale: 4,
                    units: "meters",
                    anchor: "center",
                    tooltip: false,
                    // adjustment: { x: 0.5, y: 0.5, z: 0 }, //三维模型通常不在其轴的中心，因此对象的位置和旋转错误。调整参数必须以每个轴的单位提供（即调整：{x:0.5，y:0.5，z:0}），因此模型将校正对象的中心位置
                    rotation: { x: 90, y: -180, z: 0 } // default rotation
                };
                promiseArray.push(
                    new Promise(resolve => {
                        tb.loadObj(option, model => {
                            resolve({
                                model,
                                name: item.name
                            });
                        });
                    })
                );
            });
            return Promise.all(promiseArray);
        };

        // 清除模型
        const clearBusModels = () => {
            busModels.forEach(item => {
                tb.remove(item);
            });
            busModels = [];
            if (tb) {
                tb.update();
            }
            if (map) {
                map.triggerRepaint();
            }
        };

        const onObjectChanged = e => {
            let model = e.detail.object; //here's the object already modified
            map.setCenter(model.coordinates);
        };

        const track = data => {
            var options = {
                path: data.geometry.coordinates,
                duration: 40000
            };

            busModels[0].followPath(options, () => {
                // tb.remove(line);
            });
            let lineGeometry = options.path;
            line = tb.line({
                geometry: lineGeometry,
                width: 5,
                color: "steelblue"
            });
            tb.add(line);
        };
        onMounted(() => {
            Utils.highlightCode();
        });

        onUpdated(() => {
            Utils.highlightCode();
        });

        onBeforeUnmount(() => {
            clearBusModels();
        });

        return {
            mapOptions,
            getMap,
            threeCode,
            gpsData,
            Utils,
            getTb,
            track
        };
    }
};
</script>

<style lang="scss" scoped>
.demo-content {
    width: 100%;
    height: 100%;
    padding: 16px;
    overflow: auto;
    display: flex;
    flex-direction: column;

    .field {
        display: flex;
        width: 100%;
        height: 700px;
        margin: 16px 0;
        flex: 1;
        height: 0;

        .field-left {
            flex: 1;
            height: 100%;
            width: 0;

            pre {
                margin: 0;
                padding: 0;
                height: 100%;
                display: flex;
                width: 100%;
                position: relative;

                code {
                    width: 100%;
                }
            }
        }

        .field-right {
            margin-left: 16px;
            width: 50%;
            height: 100%;
        }
    }
}
</style>
